import * as crypto from "crypto";
import * as http from "http";
import * as https from "https";
import * as vscode from "vscode";

/** 与 settings 中 wukong.licenseSecret 一致；留空时使用（仅作开发/默认分发，正式环境请改密钥） */
export const DEFAULT_LICENSE_SECRET =
  "wukong-mcp-dev-please-change-in-settings-2025";

export const GLOBAL_STATE_LICENSE_KEY = "wukong.license.v1";
export const GLOBAL_STATE_USED_NONCES_KEY = "wukong.usedLicenseNonces.v1";
export const GLOBAL_STATE_TRIAL_UNTIL_KEY = "wukong.trialUntil.v1";
export const GLOBAL_STATE_TRIAL_USED_KEY = "wukong.trialUsed.v1";

/** 试用时长（每机仅一次） */
export const TRIAL_DURATION_MS = 30 * 60 * 1000;

const MAX_STORED_NONCES = 4000;

/** 1 分钟 */
export const MIN_LICENSE_DURATION_MS = 60 * 1000;
/** 10 年（上限，防误填） */
export const MAX_LICENSE_DURATION_MS = 10 * 365 * 24 * 3600 * 1000;

export type DurKind = "perm" | "1d" | "1h" | "timed";

type LicensePayload =
  | { v: 1; dur: "perm" | "1d" | "1h"; nonce: string }
  | { v: 1; dur: "timed"; durationMs: number; nonce: string };

export interface StoredLicense {
  activatedAt: number;
  expiresAt: number | null;
  nonce: string;
  dur: DurKind;
  /** 仅 timed 卡有意义，便于展示 */
  durationMs?: number;
  /** 云端核销返回的 code_hash，用于定期调用 /api/license/verify（吊销后清除本机授权） */
  cloudCodeHash?: string;
}

export function getLicenseSecret(): string {
  const cfg = vscode.workspace.getConfiguration("wukong");
  const s = cfg.get<string>("licenseSecret");
  if (typeof s === "string" && s.trim().length >= 8) {
    return s.trim();
  }
  return DEFAULT_LICENSE_SECRET;
}

function toBase64Url(buf: Buffer): string {
  return buf
    .toString("base64")
    .replace(/\+/g, "-")
    .replace(/\//g, "_")
    .replace(/=+$/, "");
}

function fromBase64Url(s: string): Buffer {
  const pad = s.length % 4 === 0 ? "" : "=".repeat(4 - (s.length % 4));
  const b64 = s.replace(/-/g, "+").replace(/_/g, "/") + pad;
  return Buffer.from(b64, "base64");
}

function clampDurationMs(ms: number): number {
  const x = Math.floor(ms);
  if (!Number.isFinite(x)) {
    return MIN_LICENSE_DURATION_MS;
  }
  if (x < MIN_LICENSE_DURATION_MS) {
    return MIN_LICENSE_DURATION_MS;
  }
  if (x > MAX_LICENSE_DURATION_MS) {
    return MAX_LICENSE_DURATION_MS;
  }
  return x;
}

function signPayload(secret: string, dur: string, nonce: string, durationMs?: number): Buffer {
  const n = nonce.toLowerCase();
  if (dur === "timed") {
    if (durationMs === undefined) {
      throw new Error("timed 卡密缺少 durationMs");
    }
    const msInt = clampDurationMs(durationMs);
    const msg = `v1|1|timed|${n}|${msInt}`;
    return crypto.createHmac("sha256", secret).update(msg, "utf8").digest();
  }
  const msg = `v1|1|${dur}|${n}`;
  return crypto.createHmac("sha256", secret).update(msg, "utf8").digest();
}

/**
 * 生成卡密（管理员侧，与当前密钥一致）。
 * `dur === "timed"` 时必须传入 `durationMs`（激活后起算的毫秒数，会被限制在合法区间内）。
 */
export function generateLicenseToken(secret: string, dur: DurKind, durationMs?: number): string {
  const nonce = crypto.randomBytes(16).toString("hex");
  let payload: LicensePayload;
  let sig: Buffer;
  if (dur === "timed") {
    if (durationMs === undefined || typeof durationMs !== "number" || !Number.isFinite(durationMs)) {
      throw new Error("自定义时长卡密需要有效的 durationMs（毫秒）");
    }
    const ms = clampDurationMs(durationMs);
    payload = { v: 1, dur: "timed", durationMs: ms, nonce };
    sig = signPayload(secret, "timed", nonce, ms);
  } else {
    payload = { v: 1, dur, nonce };
    sig = signPayload(secret, dur, nonce);
  }
  const pB64 = toBase64Url(Buffer.from(JSON.stringify(payload), "utf8"));
  const sB64 = toBase64Url(sig);
  return `WKM1.${pB64}.${sB64}`;
}

type ParseOk =
  | { ok: true; dur: "perm" | "1d" | "1h"; nonce: string }
  | { ok: true; dur: "timed"; nonce: string; durationMs: number };

export function verifyAndParseToken(secret: string, token: string): ParseOk | { ok: false; error: string } {
  const raw = token.trim().replace(/\s+/g, "");
  const parts = raw.split(".");
  if (parts.length !== 3 || parts[0] !== "WKM1") {
    return { ok: false, error: "卡密格式不正确（应以 WKM1. 开头）" };
  }
  let payload: unknown;
  try {
    payload = JSON.parse(fromBase64Url(parts[1]).toString("utf8"));
  } catch {
    return { ok: false, error: "卡密数据无法解析" };
  }
  if (!payload || typeof payload !== "object") {
    return { ok: false, error: "卡密数据无效" };
  }
  const p = payload as Record<string, unknown>;
  if (p.v !== 1) {
    return { ok: false, error: "不支持的卡密版本" };
  }
  const dur = p.dur;
  if (dur !== "perm" && dur !== "1d" && dur !== "1h" && dur !== "timed") {
    return { ok: false, error: "卡密类型无效" };
  }
  const nonce = String(p.nonce ?? "");
  if (!/^[0-9a-f]{32}$/i.test(nonce)) {
    return { ok: false, error: "卡密校验失败" };
  }
  let durationMs: number | undefined;
  if (dur === "timed") {
    const rawMs = p.durationMs;
    if (typeof rawMs !== "number" || !Number.isFinite(rawMs)) {
      return { ok: false, error: "自定义时长卡密缺少有效的 durationMs" };
    }
    durationMs = clampDurationMs(rawMs);
  }
  let sigBuf: Buffer;
  try {
    sigBuf = fromBase64Url(parts[2]);
  } catch {
    return { ok: false, error: "签名块无效" };
  }
  if (sigBuf.length !== 32) {
    return { ok: false, error: "签名校验失败" };
  }
  const expected =
    dur === "timed"
      ? signPayload(secret, "timed", nonce, durationMs)
      : signPayload(secret, dur, nonce);
  if (!crypto.timingSafeEqual(sigBuf, expected)) {
    return { ok: false, error: "卡密无效或与当前签名密钥不匹配（请检查设置 wukong.licenseSecret）" };
  }
  if (dur === "timed") {
    if (durationMs === undefined) {
      return { ok: false, error: "卡密数据不完整" };
    }
    return { ok: true, dur: "timed", nonce: nonce.toLowerCase(), durationMs };
  }
  return { ok: true, dur: dur as "perm" | "1d" | "1h", nonce: nonce.toLowerCase() };
}

function readUsedNonces(context: vscode.ExtensionContext): string[] {
  const raw = context.globalState.get<unknown>(GLOBAL_STATE_USED_NONCES_KEY);
  if (!Array.isArray(raw)) return [];
  return raw.map((x) => String(x).toLowerCase()).filter((x) => /^[0-9a-f]{32}$/.test(x));
}

function checkStoredLicenseOnly(context: vscode.ExtensionContext): {
  valid: boolean;
  expiresAt: number | null;
  dur?: DurKind;
} {
  const raw = context.globalState.get<unknown>(GLOBAL_STATE_LICENSE_KEY);
  if (!raw || typeof raw !== "object" || Array.isArray(raw)) {
    return { valid: false, expiresAt: null };
  }
  const o = raw as Record<string, unknown>;
  const expiresAt = o.expiresAt;
  const dur = o.dur as DurKind | undefined;
  if (expiresAt === null || expiresAt === undefined) {
    if (dur === "perm" || dur === undefined) {
      return { valid: true, expiresAt: null, dur: "perm" };
    }
    return { valid: false, expiresAt: null };
  }
  if (typeof expiresAt !== "number") {
    return { valid: false, expiresAt: null };
  }
  if (Date.now() >= expiresAt) {
    return { valid: false, expiresAt };
  }
  return { valid: true, expiresAt, dur };
}

export function checkLicenseValidity(context: vscode.ExtensionContext): {
  valid: boolean;
  expiresAt: number | null;
  dur?: DurKind;
  /** 当前为一次性试用（非卡密） */
  isTrial?: boolean;
} {
  const lic = checkStoredLicenseOnly(context);
  if (lic.valid) {
    return { ...lic, isTrial: false };
  }
  const trialUntil = context.globalState.get<unknown>(GLOBAL_STATE_TRIAL_UNTIL_KEY);
  if (typeof trialUntil === "number" && Date.now() < trialUntil) {
    return { valid: true, expiresAt: trialUntil, isTrial: true };
  }
  return { valid: false, expiresAt: null };
}

export function formatLicenseExpiry(expiresAt: number | null): string {
  if (expiresAt === null) {
    return "已激活 · 永久";
  }
  const ms = expiresAt - Date.now();
  if (ms <= 0) {
    return "已过期";
  }
  const totalM = Math.floor(ms / 60000);
  const d = Math.floor(totalM / (60 * 24));
  const h = Math.floor((totalM - d * 60 * 24) / 60);
  const m = totalM % 60;
  if (d > 0) {
    return `已激活 · 剩余约 ${d} 天 ${h} 小时`;
  }
  if (h > 0) {
    return `已激活 · 剩余约 ${h} 小时 ${m} 分钟`;
  }
  if (totalM < 1) {
    const sec = Math.max(1, Math.ceil(ms / 1000));
    return `已激活 · 剩余约 ${sec} 秒`;
  }
  return `已激活 · 剩余约 ${m} 分钟`;
}

export function getLicenseStatusForWebview(context: vscode.ExtensionContext): {
  ok: boolean;
  expiresAt: number | null;
  label: string;
} {
  const st = checkLicenseValidity(context);
  if (!st.valid) {
    return { ok: false, expiresAt: null, label: "未激活" };
  }
  if (st.isTrial && st.expiresAt !== null) {
    return {
      ok: true,
      expiresAt: st.expiresAt,
      label: formatLicenseExpiry(st.expiresAt).replace("已激活", "试用中"),
    };
  }
  return {
    ok: true,
    expiresAt: st.expiresAt,
    label: formatLicenseExpiry(st.expiresAt),
  };
}

function postJsonToCloud(
  baseUrl: string,
  pathname: string,
  body: Record<string, unknown>,
  timeoutMs: number
): Promise<{ statusCode: number; raw: string }> {
  let u: URL;
  try {
    u = new URL(pathname, baseUrl.replace(/\/+$/, ""));
  } catch {
    return Promise.reject(new Error("redeemApiBaseUrl 格式无效"));
  }
  const payload = Buffer.from(JSON.stringify(body), "utf8");
  const lib = u.protocol === "https:" ? https : http;
  const port =
    u.port !== "" ? parseInt(u.port, 10) : u.protocol === "https:" ? 443 : 80;
  return new Promise((resolve, reject) => {
    const req = lib.request(
      {
        hostname: u.hostname,
        port,
        path: `${u.pathname}${u.search}`,
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Content-Length": String(payload.length),
        },
      },
      (res) => {
        const chunks: Buffer[] = [];
        res.on("data", (c: Buffer) => chunks.push(c));
        res.on("end", () => {
          resolve({
            statusCode: res.statusCode ?? 0,
            raw: Buffer.concat(chunks).toString("utf8"),
          });
        });
      }
    );
    req.on("error", reject);
    req.setTimeout(timeoutMs, () => {
      req.destroy();
      reject(new Error("连接超时"));
    });
    req.write(payload);
    req.end();
  });
}

function postRedeemToCloud(
  baseUrl: string,
  body: { code: string; user: string | null },
  timeoutMs: number
): Promise<{ statusCode: number; raw: string }> {
  return postJsonToCloud(baseUrl, "/api/redeem", body, timeoutMs);
}

/**
 * 激活：以 `WKM1.` 开头的走本地 HMAC 卡密；否则请求云端 `redeemApiBaseUrl` + `/api/redeem` 核销后写入本机授权（永久）。
 */
export async function tryActivateLicenseAsync(
  context: vscode.ExtensionContext,
  keyInput: string
): Promise<{ ok: boolean; msg: string }> {
  const key = keyInput.trim().replace(/\s+/g, "");
  if (!key) {
    return { ok: false, msg: "请输入卡密" };
  }
  const cur = checkLicenseValidity(context);
  if (cur.valid && !cur.isTrial) {
    return { ok: false, msg: "本机已激活且未过期，无需重复激活" };
  }

  const cfg = vscode.workspace.getConfiguration("wukong");

  if (key.startsWith("WKM1.")) {
    const cloudOnly = cfg.get<boolean>("cloudLicenseOnly") !== false;
    if (cloudOnly) {
      return {
        ok: false,
        msg: "当前为仅云端卡密模式：请使用发卡系统生成的卡密格式（可在设置中将 wukong.cloudLicenseOnly 设为 false 以使用 WKM1 本地卡密）。",
      };
    }
    return tryActivateLicense(context, keyInput);
  }

  const baseRaw = cfg.get<string>("redeemApiBaseUrl");
  const baseUrl = typeof baseRaw === "string" ? baseRaw.trim() : "";
  if (!baseUrl) {
    return {
      ok: false,
      msg: "未配置云端核销地址：请在设置中填写 wukong.redeemApiBaseUrl（例如 http://5245.fun）",
    };
  }

  const rawTimeout = cfg.get<number>("redeemTimeoutMs");
  const timeoutMs = Math.min(
    120000,
    Math.max(3000, typeof rawTimeout === "number" && Number.isFinite(rawTimeout) ? rawTimeout : 20000)
  );

  let machineId = vscode.env.machineId || "unknown";
  if (machineId === "someValue.machineId") {
    machineId = "dev-machine";
  }

  let res: { statusCode: number; raw: string };
  try {
    res = await postRedeemToCloud(
      baseUrl,
      { code: key, user: machineId.length > 128 ? machineId.slice(0, 128) : machineId },
      timeoutMs
    );
  } catch (e) {
    const err = e instanceof Error ? e.message : String(e);
    return { ok: false, msg: `无法连接核销服务：${err}` };
  }

  let data: {
    ok?: boolean;
    error?: string;
    licenseExpiresAt?: string | null;
    codeHash?: string;
  };
  try {
    data = JSON.parse(res.raw) as {
      ok?: boolean;
      error?: string;
      licenseExpiresAt?: string | null;
      codeHash?: string;
    };
  } catch {
    return { ok: false, msg: `服务器返回异常（HTTP ${res.statusCode}）` };
  }

  if (data.ok !== true) {
    const err = typeof data.error === "string" ? data.error : "invalid_or_used";
    if (err === "invalid_or_used") {
      return { ok: false, msg: "卡密无效或已被使用" };
    }
    return { ok: false, msg: "核销失败，请稍后再试" };
  }

  const now = Date.now();
  const nonce = `cloud:${crypto.randomBytes(16).toString("hex")}`;
  const cloudCodeHash =
    typeof data.codeHash === "string" && /^[0-9a-f]{64}$/i.test(data.codeHash.trim())
      ? data.codeHash.trim().toLowerCase()
      : undefined;

  let expiresAt: number | null = null;
  let dur: DurKind = "perm";
  let durationMs: number | undefined;
  if (data.licenseExpiresAt != null && typeof data.licenseExpiresAt === "string") {
    const t = Date.parse(data.licenseExpiresAt);
    if (!Number.isNaN(t) && t > now) {
      expiresAt = t;
      dur = "timed";
      durationMs = t - now;
    }
  }

  const stored: StoredLicense = {
    activatedAt: now,
    expiresAt,
    nonce,
    dur,
    ...(durationMs !== undefined ? { durationMs } : {}),
    ...(cloudCodeHash ? { cloudCodeHash } : {}),
  };
  void context.globalState.update(GLOBAL_STATE_LICENSE_KEY, stored);
  void context.globalState.update(GLOBAL_STATE_TRIAL_UNTIL_KEY, undefined);
  const sub =
    expiresAt !== null
      ? `激活成功（云端 · 约 ${Math.ceil((expiresAt - now) / 86400000)} 天）`
      : "激活成功（云端 · 永久）";
  return { ok: true, msg: sub };
}

export function tryActivateLicense(
  context: vscode.ExtensionContext,
  keyInput: string
): { ok: boolean; msg: string } {
  const key = keyInput.trim().replace(/\s+/g, "");
  if (!key) {
    return { ok: false, msg: "请输入卡密" };
  }
  const cur = checkLicenseValidity(context);
  if (cur.valid && !cur.isTrial) {
    return { ok: false, msg: "本机已激活且未过期，无需重复激活" };
  }
  const secret = getLicenseSecret();
  const parsed = verifyAndParseToken(secret, key);
  if (!parsed.ok) {
    return { ok: false, msg: parsed.error };
  }
  const used = readUsedNonces(context);
  if (used.includes(parsed.nonce)) {
    return { ok: false, msg: "此卡密已在本机使用过（一卡一用）" };
  }
  const now = Date.now();
  let expiresAt: number | null = null;
  if (parsed.dur === "timed") {
    expiresAt = now + parsed.durationMs;
  } else if (parsed.dur === "1h") {
    expiresAt = now + 3600 * 1000;
  } else if (parsed.dur === "1d") {
    expiresAt = now + 24 * 3600 * 1000;
  } else {
    expiresAt = null;
  }
  const nextUsed = [...used, parsed.nonce];
  if (nextUsed.length > MAX_STORED_NONCES) {
    nextUsed.splice(0, nextUsed.length - MAX_STORED_NONCES);
  }
  const stored: StoredLicense = {
    activatedAt: now,
    expiresAt,
    nonce: parsed.nonce,
    dur: parsed.dur,
    ...(parsed.dur === "timed" ? { durationMs: parsed.durationMs } : {}),
  };
  void context.globalState.update(GLOBAL_STATE_USED_NONCES_KEY, nextUsed);
  void context.globalState.update(GLOBAL_STATE_LICENSE_KEY, stored);
  void context.globalState.update(GLOBAL_STATE_TRIAL_UNTIL_KEY, undefined);
  return { ok: true, msg: "激活成功" };
}

/** 每机仅一次：30 分钟试用 */
export function tryStartTrial30(context: vscode.ExtensionContext): { ok: boolean; msg: string } {
  if (context.globalState.get<boolean>(GLOBAL_STATE_TRIAL_USED_KEY)) {
    return { ok: false, msg: "本机已使用过试用" };
  }
  const st = checkLicenseValidity(context);
  if (st.valid && !st.isTrial) {
    return { ok: false, msg: "当前已激活" };
  }
  if (st.valid && st.isTrial) {
    return { ok: false, msg: "试用尚未结束" };
  }
  const until = Date.now() + TRIAL_DURATION_MS;
  void context.globalState.update(GLOBAL_STATE_TRIAL_UNTIL_KEY, until);
  void context.globalState.update(GLOBAL_STATE_TRIAL_USED_KEY, true);
  return { ok: true, msg: "试用已开始" };
}

export async function clearLicenseState(context: vscode.ExtensionContext): Promise<void> {
  await context.globalState.update(GLOBAL_STATE_LICENSE_KEY, undefined);
}

export async function clearTrialUntilState(context: vscode.ExtensionContext): Promise<void> {
  await context.globalState.update(GLOBAL_STATE_TRIAL_UNTIL_KEY, undefined);
}

/** 限时授权已到期时清掉本机 license 记录（永久授权不处理） */
export function clearExpiredLicenseIfNeeded(context: vscode.ExtensionContext): void {
  const raw = context.globalState.get<unknown>(GLOBAL_STATE_LICENSE_KEY);
  if (!raw || typeof raw !== "object" || Array.isArray(raw)) return;
  const o = raw as Record<string, unknown>;
  const expiresAt = o.expiresAt;
  if (expiresAt === null || expiresAt === undefined) return;
  if (typeof expiresAt === "number" && Date.now() >= expiresAt) {
    void clearLicenseState(context);
  }
}

/** 试用到期后清除 trialUntil */
export function clearExpiredTrialIfNeeded(context: vscode.ExtensionContext): void {
  const trialUntil = context.globalState.get<unknown>(GLOBAL_STATE_TRIAL_UNTIL_KEY);
  if (typeof trialUntil === "number" && Date.now() >= trialUntil) {
    void context.globalState.update(GLOBAL_STATE_TRIAL_UNTIL_KEY, undefined);
  }
}

const CLOUD_VERIFY_FAIL_ERRORS = new Set(["revoked", "not_found", "expired", "device_mismatch"]);

/**
 * 云端卡：定期请求 /api/license/verify；服务端吊销或过期则清除本机授权。
 * 无 cloudCodeHash 的旧数据无法远程吊销；网络失败时不撤销（避免误伤离线用户）。
 */
export async function enforceCloudLicenseRevocationCheck(
  context: vscode.ExtensionContext
): Promise<void> {
  const raw = context.globalState.get<unknown>(GLOBAL_STATE_LICENSE_KEY);
  if (!raw || typeof raw !== "object" || Array.isArray(raw)) {
    return;
  }
  const o = raw as Record<string, unknown>;
  const nonce = String(o.nonce ?? "");
  if (!nonce.startsWith("cloud:")) {
    return;
  }
  const codeHash = typeof o.cloudCodeHash === "string" ? o.cloudCodeHash.trim().toLowerCase() : "";
  if (!codeHash || !/^[0-9a-f]{64}$/.test(codeHash)) {
    return;
  }

  const cfg = vscode.workspace.getConfiguration("wukong");
  const baseRaw = cfg.get<string>("redeemApiBaseUrl");
  const baseUrl = typeof baseRaw === "string" ? baseRaw.trim() : "";
  if (!baseUrl) {
    return;
  }

  const rawTimeout = cfg.get<number>("redeemTimeoutMs");
  const timeoutMs = Math.min(
    120000,
    Math.max(3000, typeof rawTimeout === "number" && Number.isFinite(rawTimeout) ? rawTimeout : 20000)
  );

  let machineId = vscode.env.machineId || "unknown";
  if (machineId === "someValue.machineId") {
    machineId = "dev-machine";
  }
  const user = machineId.length > 128 ? machineId.slice(0, 128) : machineId;

  let res: { statusCode: number; raw: string };
  try {
    res = await postJsonToCloud(
      baseUrl,
      "/api/license/verify",
      { codeHash, user },
      timeoutMs
    );
  } catch {
    return;
  }

  let data: { ok?: boolean; error?: string };
  try {
    data = JSON.parse(res.raw) as { ok?: boolean; error?: string };
  } catch {
    return;
  }

  if (data.ok === true) {
    return;
  }
  const err = typeof data.error === "string" ? data.error : "";
  if (CLOUD_VERIFY_FAIL_ERRORS.has(err)) {
    await clearLicenseState(context);
  }
}
